+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Stores preferences in-memory keyed by userId. Users who have not
+ * explicitly set preferences get defaults (all enabled, immediate frequency).
+ */
+
+import type { NotificationType } from '../models/notification.js';
+import type {
+  UserPreferences,
+  UpdatePreferencesInput,
+} from '../models/user-preferences.js';
+import { createDefaultPreferences } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+  private preferences: Map<string, UserPreferences> = new Map();
+
+  /**
+   * Get preferences for a user. Returns defaults if none have been set.
+   */
+  getPreferences(userId: string): UserPreferences {
+    const existing = this.preferences.get(userId);
+    if (existing) {
+      return { ...existing, subscribedCategories: [...existing.subscribedCategories] };
+    }
+    return createDefaultPreferences(userId);
+  }
+
+  /**
+   * Update preferences for a user. Creates preferences if they don't exist.
+   * Only the fields present in the input are changed.
+   */
+  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
+    const current = this.getPreferences(userId);
+
+    const updated: UserPreferences = {
+      ...current,
+      ...(input.emailEnabled !== undefined && { emailEnabled: input.emailEnabled }),
+      ...(input.emailFrequency !== undefined && { emailFrequency: input.emailFrequency }),
+      ...(input.subscribedCategories !== undefined && {
+        subscribedCategories: [...input.subscribedCategories],
+      }),
+      updatedAt: new Date(),
+    };
+
+    this.preferences.set(userId, updated);
+    this.logger.info(`Updated preferences for user ${userId}`);
+    return { ...updated, subscribedCategories: [...updated.subscribedCategories] };
+  }
+
+  /**
+   * Check whether a notification should be sent to a user based on their preferences.
+   * Returns true if the notification should be delivered immediately.
+   */
+  shouldSendNotification(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.getPreferences(userId);
+
+    if (!prefs.emailEnabled) {
+      return false;
+    }
+
+    if (!prefs.subscribedCategories.includes(notificationType)) {
+      return false;
+    }
+
+    if (prefs.emailFrequency !== 'immediate') {
+      return false;
+    }
+
+    return true;
+  }
+
+  /**
+   * Reset a user's preferences to defaults.
+   */
+  resetPreferences(userId: string): UserPreferences {
+    const defaults = createDefaultPreferences(userId);
+    this.preferences.set(userId, defaults);
+    this.logger.info(`Reset preferences for user ${userId}`);
+    return { ...defaults, subscribedCategories: [...defaults.subscribedCategories] };
+  }
+
+  /**
+   * Delete stored preferences for a user. Future calls to getPreferences
+   * will return defaults.
+   */
+  deletePreferences(userId: string): boolean {
+    const deleted = this.preferences.delete(userId);
+    if (deleted) {
+      this.logger.info(`Deleted preferences for user ${userId}`);
+    }
+    return deleted;
+  }
+
+  /**
+   * Clear all stored preferences (useful for testing).
+   */
+  clearAll(): void {
+    this.preferences.clear();
+  }
+}

