+import { describe, it, expect, beforeEach } from 'vitest';
+import { PreferencesService } from '../../src/services/preferences.service.js';
+import { ALL_NOTIFICATION_TYPES } from '../../src/models/user-preferences.js';
+import { EventBus } from '../../src/events/event-bus.js';
+import {
+  NotificationService,
+  resetNotificationIdCounter,
+} from '../../src/services/notification.service.js';
+import { EmailAdapter, resetEmailIdCounter } from '../../src/adapters/email.adapter.js';
+import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
+
+describe('PreferencesService', () => {
+  let service: PreferencesService;
+
+  beforeEach(() => {
+    service = new PreferencesService();
+  });
+
+  describe('getPreferences', () => {
+    it('should return default preferences for unknown user', () => {
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.userId).toBe('user-1');
+      expect(prefs.emailEnabled).toBe(true);
+      expect(prefs.emailFrequency).toBe('immediate');
+      expect(prefs.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
+    });
+
+    it('should return a copy, not a reference', () => {
+      const prefs1 = service.getPreferences('user-1');
+      const prefs2 = service.getPreferences('user-1');
+      expect(prefs1).toEqual(prefs2);
+      expect(prefs1).not.toBe(prefs2);
+      expect(prefs1.subscribedCategories).not.toBe(prefs2.subscribedCategories);
+    });
+  });
+
+  describe('updatePreferences', () => {
+    it('should update emailEnabled', () => {
+      const updated = service.updatePreferences('user-1', { emailEnabled: false });
+      expect(updated.emailEnabled).toBe(false);
+      expect(updated.emailFrequency).toBe('immediate');
+      expect(updated.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
+    });
+
+    it('should update emailFrequency', () => {
+      const updated = service.updatePreferences('user-1', { emailFrequency: 'daily_digest' });
+      expect(updated.emailFrequency).toBe('daily_digest');
+      expect(updated.emailEnabled).toBe(true);
+    });
+
+    it('should update subscribedCategories', () => {
+      const updated = service.updatePreferences('user-1', {
+        subscribedCategories: ['order_confirmation'],
+      });
+      expect(updated.subscribedCategories).toEqual(['order_confirmation']);
+    });
+
+    it('should update multiple fields at once', () => {
+      const updated = service.updatePreferences('user-1', {
+        emailEnabled: false,
+        emailFrequency: 'weekly_digest',
+        subscribedCategories: ['welcome'],
+      });
+      expect(updated.emailEnabled).toBe(false);
+      expect(updated.emailFrequency).toBe('weekly_digest');
+      expect(updated.subscribedCategories).toEqual(['welcome']);
+    });
+
+    it('should persist changes', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      const prefs = service.getPreferences('user-1');
+      expect(prefs.emailEnabled).toBe(false);
+    });
+
+    it('should return a copy', () => {
+      const updated = service.updatePreferences('user-1', { emailEnabled: false });
+      updated.emailEnabled = true;
+      expect(service.getPreferences('user-1').emailEnabled).toBe(false);
+    });
+  });
+
+  describe('shouldSendNotification', () => {
+    it('should return true for default preferences', () => {
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
+      expect(service.shouldSendNotification('user-1', 'welcome')).toBe(true);
+    });
+
+    it('should return false when email is disabled', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
+    });
+
+    it('should return false for unsubscribed category', () => {
+      service.updatePreferences('user-1', {
+        subscribedCategories: ['order_confirmation'],
+      });
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(true);
+      expect(service.shouldSendNotification('user-1', 'welcome')).toBe(false);
+    });
+
+    it('should return false for non-immediate frequency', () => {
+      service.updatePreferences('user-1', { emailFrequency: 'daily_digest' });
+      expect(service.shouldSendNotification('user-1', 'order_confirmation')).toBe(false);
+    });
+  });
+
+  describe('resetPreferences', () => {
+    it('should reset to defaults', () => {
+      service.updatePreferences('user-1', { emailEnabled: false, emailFrequency: 'weekly_digest' });
+      const reset = service.resetPreferences('user-1');
+      expect(reset.emailEnabled).toBe(true);
+      expect(reset.emailFrequency).toBe('immediate');
+      expect(reset.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
+    });
+  });
+
+  describe('deletePreferences', () => {
+    it('should delete stored preferences', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      expect(service.deletePreferences('user-1')).toBe(true);
+      expect(service.getPreferences('user-1').emailEnabled).toBe(true);
+    });
+
+    it('should return false when no preferences exist', () => {
+      expect(service.deletePreferences('user-1')).toBe(false);
+    });
+  });
+
+  describe('clearAll', () => {
+    it('should clear all preferences', () => {
+      service.updatePreferences('user-1', { emailEnabled: false });
+      service.updatePreferences('user-2', { emailEnabled: false });
+      service.clearAll();
+      expect(service.getPreferences('user-1').emailEnabled).toBe(true);
+      expect(service.getPreferences('user-2').emailEnabled).toBe(true);
+    });
+  });
+});
+
+describe('NotificationService with preferences', () => {
+  let eventBus: EventBus;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+  let emailAdapter: EmailAdapter;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    notificationService = new NotificationService(eventBus);
+    preferencesService = new PreferencesService();
+    notificationService.setPreferencesService(preferencesService);
+    emailAdapter = new EmailAdapter();
+    notificationService.registerAdapter(emailAdapter);
+    resetNotificationIdCounter();
+    resetEmailIdCounter();
+  });
+
+  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
+    type: 'order:created',
+    order: {
+      id: 'order-1',
+      userId,
+      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+      total: 10,
+      status: 'pending',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    user: {
+      id: userId,
+      name: 'Alice',
+      email,
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+  });
+
+  const makeUserCreatedEvent = (userId: string, email: string): UserCreatedEvent => ({
+    type: 'user:created',
+    user: {
+      id: userId,
+      name: 'Alice',
+      email,
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+  });
+
+  it('should send notification with default preferences', async () => {
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(1);
+    expect(emailAdapter.getSentEmails()).toHaveLength(1);
+  });
+
+  it('should suppress notification when email is disabled', async () => {
+    preferencesService.updatePreferences('user-1', { emailEnabled: false });
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(0);
+    expect(emailAdapter.getSentEmails()).toHaveLength(0);
+  });
+
+  it('should suppress notification for unsubscribed category', async () => {
+    preferencesService.updatePreferences('user-1', {
+      subscribedCategories: ['welcome'],
+    });
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(0);
+  });
+
+  it('should suppress notification for non-immediate frequency', async () => {
+    preferencesService.updatePreferences('user-1', { emailFrequency: 'daily_digest' });
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(0);
+  });
+
+  it('should send welcome but suppress order for selective subscription', async () => {
+    preferencesService.updatePreferences('user-1', {
+      subscribedCategories: ['welcome'],
+    });
+
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    await eventBus.emit(makeUserCreatedEvent('user-1', 'alice@example.com'));
+
+    const notifications = notificationService.getNotifications();
+    expect(notifications).toHaveLength(1);
+    expect(notifications[0]?.type).toBe('welcome');
+  });
+
+  it('should allow notifications after re-enabling email', async () => {
+    preferencesService.updatePreferences('user-1', { emailEnabled: false });
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(0);
+
+    preferencesService.updatePreferences('user-1', { emailEnabled: true });
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    expect(notificationService.getNotifications()).toHaveLength(1);
+  });
+
+  it('should work without preferences service (backward compatible)', async () => {
+    const plainService = new NotificationService(eventBus);
+    plainService.registerAdapter(new EmailAdapter());
+
+    await eventBus.emit(makeOrderCreatedEvent('user-1', 'alice@example.com'));
+    // Both services received the event (both subscribed to the same eventBus)
+    expect(plainService.getNotifications()).toHaveLength(1);
+  });
+});

